mapper.select:
SELECT count(*) FROM inventory_item

    AND product_id = #{productId}
    AND sku = #{sku}
    AND variant_id = #{variantId}
    AND status = #{status}
    AND "stateId" = #{stateId}
    AND primary_fc = #{primaryFc}

SELECT
    id, sku,
    product_id as "productId",
    variant_id as "variantId",
    quantity,
    available_quantity as "availableQuantity",
    reserved_quantity as "reserved",
    damaged_quantity as "damagedQuantity",
    inbound_quantity as "inboundQuantity",
    low_stock_threshold as "lowStockThreshold",
    status,
    primary_fc as "primaryFc",
    "stateId" as "stateId"
FROM inventory_item

    AND product_id = #{productId}
    AND sku = #{sku}
    AND variant_id = #{variantId}
    AND status = #{status}
    AND "stateId" = #{stateId}
    AND primary_fc = #{primaryFc}

${orderby} ${pagination}

SELECT i.primary_fc as "fulfillmentCenter", d.damage_type as "damageType", d.status as "status", COUNT(*) as "count" FROM inventory_damage_records d JOIN inventory_item i ON d.inventory_item_id = i.id
AND i.primary_fc = #{primaryFc} AND d.status = #{status}
GROUP BY i.primary_fc, d.damage_type, d.status ORDER BY "count" DESC

SELECT m.inventory_item_id as "inventoryItemId", i.sku as "sku", i.product_id as "productId", m.type as "type", m.quantity as "quantity", m.reference_id as "referenceId", m.fulfillment_center_id as "fulfillmentCenterId", m.movement_time as "movementTime", m.reason as "reason" FROM inventory_movements m JOIN inventory_item i ON m.inventory_item_id = i.id
AND m.type = #{type} AND m.inventory_item_id = #{inventoryItemId} AND m.fulfillment_center_id = #{fulfillmentCenterId}
ORDER BY m.movement_time DESC
